/**
 * ocean-mask.ts — 自动生成，请勿手动编辑
 * 
 * 全球海洋/陆地网格（0.25° 分辨率）
 * 来源：Natural Earth 110m land polygons
 * 生成时间：2026-03-25T08:01:04.874Z
 * 
 * 网格规格：
 * - 1440 列 × 720 行 = 1036800 格子
 * - 分辨率：0.25°（每格约 28 km at equator）
 * - row 0 = 90°N, col 0 = 180°W
 * - 每个格子 1 bit: 0=海洋, 1=陆地
 */

export const OCEAN_MASK_COLS = 1440;
export const OCEAN_MASK_ROWS = 720;
export const OCEAN_MASK_RESOLUTION = 0.25;

/** 
 * Packed hex string: 129600 bytes = 259200 hex chars
 * 340149 land cells, 696651 ocean cells
 */
export const OCEAN_MASK_HEX = '';

/** 检查给定经纬度是否为陆地 */
export function isLand(lat: number, lon: number): boolean {
  const row = Math.floor((90 - lat) / 0.25);
  const col = Math.floor((lon + 180) / 0.25);
  if (row < 0 || row >= 720 || col < 0 || col >= 1440) return false;
  const bitIndex = row * 1440 + col;
  const byteIndex = Math.floor(bitIndex / 8);
  const bitOffset = 7 - (bitIndex % 8);
  const byteVal = parseInt(OCEAN_MASK_HEX.substr(byteIndex * 2, 2), 16);
  return ((byteVal >> bitOffset) & 1) === 1;
}

/** 检查给定经纬度是否为海洋 */
export function isOcean(lat: number, lon: number): boolean {
  return !isLand(lat, lon);
}
